const UNITS = [
  ['ms', 1],
  ['s', 1000],
  ['m', 60000],
  ['h', 3600000],
  ['d', 86400000],
];

function parseDuration(str) {
  if (typeof str !== 'string' || str.length === 0) {
    throw new Error(`parseDuration: unparseable input: ${JSON.stringify(str)}`);
  }

  // Bare integer — no unit — is milliseconds
  if (/^\d+$/.test(str)) {
    return Number(str);
  }

  let total = 0;
  let pos = 0;

  while (pos < str.length) {
    // Consume digits
    let numStart = pos;
    while (pos < str.length && str[pos] >= '0' && str[pos] <= '9') pos++;
    if (pos === numStart) {
      throw new Error(`parseDuration: unparseable input at position ${pos}: ${JSON.stringify(str)}`);
    }
    const num = Number(str.slice(numStart, pos));

    // Match unit — ms must be checked before m
    let matched = false;
    for (const [unit, ms] of UNITS) {
      if (str.startsWith(unit, pos)) {
        total += num * ms;
        pos += unit.length;
        matched = true;
        break;
      }
    }
    if (!matched) {
      throw new Error(`parseDuration: unknown unit at position ${pos}: ${JSON.stringify(str)}`);
    }
  }

  return total;
}

